using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Tianyou.Domain.Entities;
using Tianyou.Infrastructure.Data;
using Tianyou.Application.Security;

namespace Tianyou.Application.Services;

/// <summary>
/// 代码生成服务
/// </summary>
public class CodeGeneratorService
{
    private readonly TianyouDbContext _context;
    private readonly ILogger<CodeGeneratorService> _logger;

    public CodeGeneratorService(TianyouDbContext context, ILogger<CodeGeneratorService> logger)
    {
        _context = context;
        _logger = logger;
    }

    public async Task<string> GenerateEntityCodeAsync(Guid entityId)
    {
        var entity = await _context.EntityDefinitions
            .Include(e => e.Fields)
            .FirstOrDefaultAsync(e => e.Id == entityId);

        if (entity == null)
        {
            _logger.LogWarning("生成代码失败：实体不存在 - EntityId: {EntityId}", entityId);
            throw new Exception("实体不存在");
        }

        // XSS防护：清理实体名称和描述
        var safeEntityName = XssProtector.SanitizeIdentifier(entity.EntityName, "实体名称");
        var safeDescription = XssProtector.SanitizeHtml(entity.Description);

        var code = $@"using System.ComponentModel.DataAnnotations;

namespace Tianyou.Domain.Entities;

/// <summary>
/// {safeEntityName}
/// </summary>
public class {safeEntityName}
{{
";
        foreach (var field in entity.Fields)
        {
            // XSS防护：清理字段名称
            var safeFieldName = XssProtector.SanitizeIdentifier(field.FieldName, "字段名称");
            var safeMaxLength = field.MaxLength.HasValue ? $"(MaxLength = {field.MaxLength})" : "";

            code += $@"    [Required{safeMaxLength}]
    public {GetCSharpType(field.FieldType)} {safeFieldName} {{ get; set; }}
";
        }

        code += @"}
";

        _logger.LogInformation("代码生成成功 - EntityId: {EntityId}, EntityName: {EntityName}", entityId, safeEntityName);

        return code;
    }

    public async Task<CodeTemplate> CreateTemplateAsync(string templateName, string templateType, 
        string templateContent, string? description = null, string? language = "csharp")
    {
        // XSS防护：清理所有输入
        var safeTemplateName = XssProtector.SanitizeHtml(templateName);
        var safeTemplateType = XssProtector.SanitizeHtml(templateType);
        var safeTemplateContent = XssProtector.ValidateAndSanitize(templateContent, "模板内容");
        var safeDescription = XssProtector.SanitizeHtml(description);
        var safeLanguage = XssProtector.SanitizeHtml(language);

        var template = new CodeTemplate
        {
            Id = Guid.NewGuid(),
            TemplateName = safeTemplateName,
            TemplateType = safeTemplateType,
            TemplateContent = safeTemplateContent,
            Description = safeDescription,
            Language = safeLanguage,
            IsSystem = false,
            CreatedAt = DateTime.UtcNow,
            UpdatedAt = DateTime.UtcNow
        };

        _context.CodeTemplates.Add(template);
        await _context.SaveChangesAsync();

        _logger.LogInformation("模板创建成功 - TemplateId: {TemplateId}, TemplateName: {TemplateName}", 
            template.Id, template.TemplateName);

        return template;
    }

    public async Task<List<CodeTemplate>> GetTemplatesAsync(string? templateType = null)
    {
        var query = _context.CodeTemplates.AsQueryable();

        if (!string.IsNullOrEmpty(templateType))
        {
            // XSS防护：清理模板类型
            var safeTemplateType = XssProtector.SanitizeHtml(templateType);
            query = query.Where(t => t.TemplateType == safeTemplateType);
        }

        var templates = await query.OrderBy(t => t.TemplateName).ToListAsync();

        _logger.LogInformation("查询模板列表 - TemplateType: {TemplateType}, Count: {Count}", 
            templateType ?? "all", templates.Count);

        return templates;
    }

    private string GetCSharpType(string fieldType)
    {
        return fieldType.ToLower() switch
        {
            "text" or "string" => "string",
            "number" or "int" => "int",
            "decimal" or "money" => "decimal",
            "bool" or "boolean" => "bool",
            "date" or "datetime" => "DateTime",
            "guid" => "Guid",
            _ => "string"
        };
    }
}

using System.Text;
using System.Text.RegularExpressions;

namespace Tianyou.Application.Security;

/// <summary>
/// XSS防护帮助类
/// </summary>
public static class XssProtector
{
    // 危险的HTML标签
    private static readonly string[] DangerousTags = 
    {
        "script", "iframe", "object", "embed", "form", 
        "input", "button", "textarea", "select", "style",
        "link", "meta", "base", "frame", "frameset"
    };

    // 危险的HTML属性
    private static readonly string[] DangerousAttributes = 
    {
        "onload", "onerror", "onclick", "onmouseover", "onmouseout",
        "onkeydown", "onkeyup", "onfocus", "onblur", "onsubmit",
        "onchange", "ondblclick", "oncontextmenu", "onwheel"
    };

    // 危险的模式
    private static readonly Regex ScriptPattern = new(
        @"<script.*?>.*?</script>",
        RegexOptions.Compiled | RegexOptions.IgnoreCase | RegexOptions.Singleline);

    private static readonly Regex EventPattern = new(
        @"on\w+\s*=",
        RegexOptions.Compiled | RegexOptions.IgnoreCase);

    private static readonly Regex JavaScriptPattern = new(
        @"javascript\s*:",
        RegexOptions.Compiled | RegexOptions.IgnoreCase);

    private static readonly Regex DataUrlPattern = new(
        @"data\s*:\s*text/html",
        RegexOptions.Compiled | RegexOptions.IgnoreCase);

    /// <summary>
    /// HTML编码 - 防止XSS攻击
    /// </summary>
    public static string HtmlEncode(string? input)
    {
        if (string.IsNullOrEmpty(input))
        {
            return string.Empty;
        }

        var sb = new StringBuilder(input.Length);
        foreach (var c in input)
        {
            switch (c)
            {
                case '<':
                    sb.Append("&lt;");
                    break;
                case '>':
                    sb.Append("&gt;");
                    break;
                case '"':
                    sb.Append("&quot;");
                    break;
                case '\'':
                    sb.Append("&#x27;");
                    break;
                case '&':
                    sb.Append("&amp;");
                    break;
                case '/':
                    sb.Append("&#x2F;");
                    break;
                default:
                    sb.Append(c);
                    break;
            }
        }
        return sb.ToString();
    }

    /// <summary>
    /// HTML解码
    /// </summary>
    public static string HtmlDecode(string? input)
    {
        if (string.IsNullOrEmpty(input))
        {
            return string.Empty;
        }

        return input
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#x27;", "'")
            .Replace("&amp;", "&")
            .Replace("&#x2F;", "/");
    }

    /// <summary>
    /// 清理HTML - 移除危险的标签和属性
    /// </summary>
    public static string SanitizeHtml(string? input)
    {
        if (string.IsNullOrEmpty(input))
        {
            return string.Empty;
        }

        var result = input;

        // 移除script标签
        result = ScriptPattern.Replace(result, string.Empty);

        // 移除事件处理器
        result = EventPattern.Replace(result, string.Empty);

        // 移除javascript:协议
        result = JavaScriptPattern.Replace(result, string.Empty);

        // 移除data:text/html URL
        result = DataUrlPattern.Replace(result, string.Empty);

        // 移除危险标签
        foreach (var tag in DangerousTags)
        {
            var tagPattern = new Regex(
                $@"<{tag}.*?>.*?</{tag}>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline);
            result = tagPattern.Replace(result, string.Empty);

            var selfClosingPattern = new Regex(
                $@"<{tag}.*?/>",
                RegexOptions.IgnoreCase);
            result = selfClosingPattern.Replace(result, string.Empty);
        }

        return result.Trim();
    }

    /// <summary>
    /// 验证字符串是否安全（不包含XSS攻击代码）
    /// </summary>
    public static bool IsSafe(string? input)
    {
        if (string.IsNullOrEmpty(input))
        {
            return true;
        }

        // 检查是否包含script标签
        if (ScriptPattern.IsMatch(input))
        {
            return false;
        }

        // 检查是否包含事件处理器
        if (EventPattern.IsMatch(input))
        {
            return false;
        }

        // 检查是否包含javascript:协议
        if (JavaScriptPattern.IsMatch(input))
        {
            return false;
        }

        // 检查是否包含data:text/html
        if (DataUrlPattern.IsMatch(input))
        {
            return false;
        }

        return true;
    }

    /// <summary>
    /// 验证并清理输入（如果发现XSS攻击则抛出异常）
    /// </summary>
    public static string ValidateAndSanitize(string? input, string fieldName = "输入")
    {
        if (string.IsNullOrEmpty(input))
        {
            return string.Empty;
        }

        if (!IsSafe(input))
        {
            throw new ArgumentException($"{fieldName}包含不安全的内容");
        }

        return SanitizeHtml(input);
    }

    /// <summary>
    /// 对代码生成器输出进行编码（保留代码格式）
    /// </summary>
    public static string EncodeForCodeGeneration(string? input)
    {
        if (string.IsNullOrEmpty(input))
        {
            return string.Empty;
        }

        // 只编码最危险的字符，保留代码格式
        return input
            .Replace("<", "&lt;")
            .Replace(">", "&gt;")
            .Replace("\"", "&quot;")
            .Replace("'", "&#x27;");
    }

    /// <summary>
    /// 对标识符进行安全检查（只允许字母、数字、下划线）
    /// </summary>
    public static string SanitizeIdentifier(string? input, string fieldName = "标识符")
    {
        if (string.IsNullOrWhiteSpace(input))
        {
            throw new ArgumentException($"{fieldName}不能为空");
        }

        // 只保留字母、数字、下划线
        var result = Regex.Replace(input, @"[^a-zA-Z0-9_]", string.Empty);

        if (string.IsNullOrEmpty(result))
        {
            throw new ArgumentException($"{fieldName}格式不正确");
        }

        return result;
    }
}

